sql:
SELECT COUNT(player_id) AS players_with_achievement
FROM player_achievements
WHERE achievement_id = 1;

SELECT username
FROM players
WHERE player_id IN (SELECT player_id FROM community_feedback);

SELECT username
FROM players
WHERE player_id IN (SELECT player_id FROM player_achievements);

external_knowledge:
; Average time invested refers to the total time spent by players in a particular game mode, averaged across all players; 
; Playtime is measured in seconds, and the query converts this to minutes for easier interpretation; 
; Game modes are unique scenarios or rulesets within a game, such as Classic or Assassins.

sql:
SELECT SUM(wins) AS total_wins
   FROM game_logs
   WHERE game_mode_id = (SELECT game_mode_id FROM game_modes WHERE game_mode_name = 'Classic');

